import { useNavigate } from "react-router-dom";
import { Button } from "@/components/ui/button";
import { Card } from "@/components/ui/card";
import { GraduationCap, Mail, Phone } from "lucide-react";

const LandingPage = () => {
  const navigate = useNavigate();

  return (
    <div className="min-h-screen bg-[#0B1120] text-white flex items-center justify-center p-6">
      <div className="max-w-3xl w-full space-y-8">

        {/* Branding */}
        <div className="text-center space-y-4">
          <div className="mx-auto w-16 h-16 bg-emerald-600 rounded-2xl flex items-center justify-center">
            <GraduationCap className="w-10 h-10 text-white" />
          </div>

          <h1 className="text-4xl font-bold">Smart-M Hub</h1>

          <p className="text-slate-400 text-lg">
            A smart school management system for administration, learning,
            finance, and communication — all in one platform.
          </p>
        </div>

        {/* Contact */}
        <Card className="bg-[#1A2332] border-[#1E3A4F] p-5 text-slate-300 space-y-2">
          <p className="flex items-center gap-2">
            <Mail className="w-4 h-4" /> support@smartmhub.com
          </p>
          <p className="flex items-center gap-2">
            <Phone className="w-4 h-4" /> +254 700 000 000
          </p>
        </Card>

        {/* Actions */}
        <div className="grid gap-4">
          <Button
            onClick={() => navigate("/setup-school")}
            className="w-full bg-emerald-600 hover:bg-emerald-500"
          >
            Register a School
          </Button>

          <Button
            onClick={() => navigate("/login")}
            variant="outline"
            className="w-full border-slate-600 text-white"
          >
            Login to Existing School
          </Button>
        </div>

      </div>
    </div>
  );
};

export default LandingPage;
